ALTER TABLE public.campaigns ADD COLUMN IF NOT EXISTS client_po_number text, ADD COLUMN IF NOT EXISTS client_po_date date, ADD COLUMN IF NOT EXISTS client_po_document_url text; COMMENT ON COLUMN public.campaigns.client_po_number IS 'Client Purchase Order or Work Order reference number'; COMMENT ON COLUMN public.campaigns.client_po_date IS 'Date of client PO/WO'; COMMENT ON COLUMN public.campaigns.client_po_document_url IS 'Uploaded PO/WO document URL'; ALTER TABLE public.invoices ADD COLUMN IF NOT EXISTS client_po_number text, ADD COLUMN IF NOT EXISTS client_po_date date; COMMENT ON COLUMN public.invoices.client_po_number IS 'Client PO/WO reference shown on invoice PDF'; COMMENT ON COLUMN public.invoices.client_po_date IS 'Client PO/WO date shown on invoice PDF';